import { useEffect, useMemo, useState } from "react";
import api from "../api";

function fmtMoney(v) {
    const n = Number(v || 0);
    try { return n.toLocaleString("vi-VN") + " ₫"; } catch { return n + " ₫"; }
}

export default function Payments() {
    const [rows, setRows] = useState([]);
    const [loading, setLoading] = useState(true);
    const [page, setPage] = useState(0);
    const size = 10;
    const [totalPages, setTotalPages] = useState(1);

    const [contractMap, setContractMap] = useState({}); // id -> code

    // nạp map hợp đồng (tối đa 1000)
    useEffect(() => { (async () => {
        try {
            const res = await api.get("/api/contracts", { params: { page: 0, size: 1000 }});
            const content = Array.isArray(res.data) ? res.data : (res.data?.content || []);
            const map = {};
            content.forEach(ct => {
                const code = ct.code || ct.contractCode || ct.title || `HD-${ct.id}`;
                map[ct.id] = code;
            });
            setContractMap(map);
        } catch {}
    })(); }, []);

    useEffect(() => { load(); }, [page]);

    async function load() {
        setLoading(true);
        try {
            const res = await api.get("/api/payments", { params: { page, size, sort: "id,desc" }});
            const data = res.data || {};
            const content = Array.isArray(data) ? data : (data.content || []);
            setRows(content);
            setTotalPages((Array.isArray(data) ? 1 : (data.totalPages ?? 1)) || 1);
        } catch (e) {
            console.error(e);
            setRows([]); setTotalPages(1);
        } finally { setLoading(false); }
    }

    const normalized = useMemo(() => rows.map(p => {
        const amount = p.amount ?? p.money ?? 0;
        const date = p.date || p.paymentDate || "";
        const method = p.method || p.paymentMethod || "";
        const status = p.status || p.paymentStatus || "";
        const confirmer = p.confirmer || p.confirmedBy || "";
        const contractCode = p.contractCode ||
            (p.contract?.code) ||
            (p.contractId ? contractMap[p.contractId] : "") ||
            (p.contractId ? `HD-${p.contractId}` : "");

        return { id: p.id, amount, date, method, status, confirmer, contractCode };
    }), [rows, contractMap]);

    return (
        <div className="p-6">
            <div className="flex items-center justify-between mb-4">
                <h2 className="text-xl font-bold">💰 Thanh toán</h2>
                <div className="text-sm text-slate-600">Trang {page+1}/{totalPages}</div>
            </div>

            {loading ? <p>Đang tải...</p> : (
                <>
                    <div className="overflow-auto">
                        <table className="min-w-full border text-sm">
                            <thead className="bg-gray-100">
                            <tr>
                                <th className="border p-2">Mã HĐ</th>
                                <th className="border p-2">Ngày</th>
                                <th className="border p-2">Số tiền</th>
                                <th className="border p-2">Phương thức</th>
                                <th className="border p-2">Trạng thái</th>
                                <th className="border p-2">Xác nhận</th>
                            </tr>
                            </thead>
                            <tbody>
                            {normalized.map(p => (
                                <tr key={p.id}>
                                    <td className="border p-2">{p.contractCode}</td>
                                    <td className="border p-2">{p.date}</td>
                                    <td className="border p-2">{fmtMoney(p.amount)}</td>
                                    <td className="border p-2">{p.method}</td>
                                    <td className="border p-2">
                      <span className={
                          "px-2 py-0.5 rounded-full text-xs " +
                          (p.status === "Đã thanh toán"
                              ? "bg-emerald-100 text-emerald-700"
                              : "bg-amber-100 text-amber-700")
                      }>
                        {p.status || "-"}
                      </span>
                                    </td>
                                    <td className="border p-2">{p.confirmer || "-"}</td>
                                </tr>
                            ))}
                            </tbody>
                        </table>
                    </div>

                    <div className="flex gap-2 mt-3">
                        <button disabled={page<=0}
                                onClick={()=>setPage(p=>Math.max(0, p-1))}
                                className="px-3 py-1 rounded bg-slate-100 disabled:opacity-50">
                            ← Trước
                        </button>
                        <button disabled={page+1>=totalPages}
                                onClick={()=>setPage(p=>p+1)}
                                className="px-3 py-1 rounded bg-slate-100 disabled:opacity-50">
                            Sau →
                        </button>
                    </div>
                </>
            )}
        </div>
    );
}
